<script setup lang="ts">
import{onMounted,ref}from'vue';type RecordItem={id:string;title:string;status:string};const API='http://localhost:8080/api',items=ref<RecordItem[]>([]),message=ref('Connecting to Java API…'),busy=ref(false);async function load(){try{const r=await fetch(`${API}/records`);if(!r.ok)throw new Error();items.value=await r.json();message.value='Java API connected'}catch{message.value='Start the Java backend on port 8080'}}async function add(){busy.value=true;try{await fetch(`${API}/records`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:'New browser learning task',note:'Created from the frontend'})});await load()}finally{busy.value=false}}onMounted(load)
</script>
<template><section class="backend-status" aria-live="polite"><strong>Full-stack connection</strong><span>{{message}} · {{items.length}} records</span><button :disabled="busy||!items.length" @click="add">{{busy?'Saving…':'Add sample learning task'}}</button></section></template>
<style scoped>.backend-status{position:fixed;right:18px;bottom:18px;z-index:50;width:min(330px,calc(100vw - 36px));padding:14px 16px;border-radius:14px;background:#111827;color:#f9fafb;box-shadow:0 14px 38px #0004;font:13px/1.4 system-ui}.backend-status strong,.backend-status span{display:block}.backend-status span{color:#cbd5e1;margin:3px 0 10px}.backend-status button{border:0;border-radius:8px;padding:8px 11px;background:#5eead4;color:#102a2a;font-weight:750}.backend-status button:disabled{opacity:.55}</style>
